/// A simple model to hold and publish promo data.
class PromoData: ObservableObject {
    @Published var promoCode: String?
    @Published var discount: String?

    func applyPromo(code: String?, discountValue: String?) {
        self.promoCode = code
        self.discount = discountValue
        print("Applied Promo - Code: \(code ?? "N/A"), Discount: \(discountValue ?? "N/A")")
        // Here you would typically integrate with your backend
        // to apply the promo code to the user's account.
    }

    func clearPromo() {
        promoCode = nil
        discount = nil
    }
}

