// MARK: - App Entry Point

@main
struct MyApp: App {
    @StateObject private var promoData = PromoData()

    var body: some Scene {
        WindowGroup {
            ContentView()
                .environmentObject(promoData)
                // This modifier is crucial for handling universal links
                // when the app is already running or launched from a link.
                .onOpenURL { url in
                    handleUniversalLink(url)
                }
        }
    }

    /// Handles the incoming URL from a universal link.
    private func handleUniversalLink(_ url: URL) {
        guard url.scheme == "https", url.host == "myapp.com", url.path == "/promo" else {
            print("Not a recognized universal link: \(url.absoluteString)")
            return
        }

        print("Received universal link: \(url.absoluteString)")

        // Parse URL components to extract query parameters
        if let components = URLComponents(url: url, resolvingAgainstBaseURL: false) {
            let promoCode = components.queryItems?.first(where: { $0.name == "code" })?.value
            let discount = components.queryItems?.first(where: { $0.name == "discount" })?.value

            if let code = promoCode, let disc = discount {
                promoData.applyPromo(code: code, discountValue: disc)
            } else {
                print("Universal link missing 'code' or 'discount' parameters.")
                promoData.clearPromo() // Clear any old promo if the link is malformed
            }
        }
    }
}

